176→func recipientsJSON(raw string) string {
177→	raw = strings.TrimSpace(raw)
178→	if raw == "" {
179→		return "[]"
180→	}
181→	parts := strings.Split(raw, ",")
182→	recipients := make([]string, 0, len(parts))
183→	for _, part := range parts {
184→		part = strings.TrimSpace(part)
185→		if part != "" {
186→			recipients = append(recipients, part)
187→		}
188→	}
189→	data, _ := json.Marshal(recipients)
190→	return string(data)
191→}
192→
193→// parseDays extracts day count from a duration string like "3d" or "72h".
194→func parseDays(delay string) int {
195→	delay = strings.TrimSpace(delay)
196→	if delay == "" || delay == "0s" {
197→		return 0
198→	}
199→	// Handle "Xd" format
200→	if strings.HasSuffix(delay, "d") {
201→		var d int
202→		fmt.Sscanf(delay, "%dd", &d)
203→		return d
204→	}
205→	// Handle "Xh" format
206→	if strings.HasSuffix(delay, "h") {
207→		var h int
208→		fmt.Sscanf(delay, "%dh", &h)
209→		return h / 24
210→	}
211→	return 3 // default
212→}
