 17→var connectorsCmd = &cobra.Command{
 18→	Use:   "connectors",
 19→	Short: "List connected services",
 20→	RunE: func(cmd *cobra.Command, args []string) error {
 21→		cfg, err := project.Load()
 22→		if err != nil {
 23→			return fmt.Errorf("loading config: %w", err)
 24→		}
 25→
 26→		registry, err := connector.LoadRegistry(projectLocalDefs)
 27→		if err != nil {
 28→			return fmt.Errorf("loading registry: %w", err)
 29→		}
 30→
 31→		hasAny := false
 32→		for _, def := range registry {
 33→			cs, ok := cfg.Connectors[def.ID]
 34→			if !ok || !cs.Connected {
 35→				continue
 36→			}
 37→			hasAny = true
 38→			fmt.Printf("  \033[32m✓\033[0m %-10s %s\n", def.Name, cs.Account)
 39→		}
 40→
 41→		if !hasAny {
 42→			fmt.Println("  No connectors configured. Run `nurge connect gmail` to connect.")
 43→		}
 44→
 45→		return nil
 46→	},
 47→}
