130→// SequenceRequest defines sequence enrollment details for a send.
131→type SequenceRequest struct {
132→	SequenceName string         `json:"sequenceName"`
133→	CampaignName string         `json:"campaignName,omitempty"`
134→	ContactName  string         `json:"contactName,omitempty"`
135→	MailboxID    string         `json:"mailboxId,omitempty"`
136→	Steps        []SequenceStep `json:"steps,omitempty"`
137→}
