139→// SequenceStep defines a future step in a sequence.
140→type SequenceStep struct {
141→	StepNumber int    `json:"stepNumber"`
142→	StepName   string `json:"stepName,omitempty"`
143→	SendType   string `json:"sendType"`
144→	DelayDays  int    `json:"delayDays"`
145→	Subject    string `json:"subject,omitempty"`
