 12→async function authenticateRequest(ctx: any, request: Request) {
 13→  const authHeader = request.headers.get("Authorization");
 14→  if (!authHeader || !authHeader.startsWith("Bearer ")) {
 15→    return { error: jsonResponse({ error: "Missing auth token" }, 401) };
 16→  }
 17→  const token = authHeader.slice(7);
 18→  const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
 19→  if (!user) {
 20→    return { error: jsonResponse({ error: "Invalid auth token" }, 401) };
 21→  }
 22→  return { user };
 23→}
 24→
 25→// POST /api/connect-gmail — returns Unipile hosted auth URL for Gmail
 26→export const connectGmail = httpAction(async (ctx, request) => {
 27→  try {
 28→    const auth = await authenticateRequest(ctx, request);
 29→    if (auth.error) return auth.error;
 30→    const user = auth.user!;
 31→
 32→    // Check if already connected
 33→    const existing = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
 34→      userId: user._id,
 35→      provider: "GOOGLE",
 36→    });
 37→    if (existing && existing.status === "connected") {
 38→      return jsonResponse({ already_connected: true, email: existing.email });
 39→    }
 40→
 41→    // Get Unipile hosted auth link
 42→    const result = await ctx.runAction(api.unipile.requestConnectionLink, {
 43→      userId: user._id,
 44→      provider: "GOOGLE",
 45→    });
 46→
 47→    return jsonResponse({ url: result.url });
 48→  } catch (error: any) {
 49→    console.error("connect-gmail error:", error);
 50→    return jsonResponse({ error: error.message }, 500);
 51→  }
 52→});
 53→
 54→// GET /api/connection-status — CLI polls this after opening auth URL
 55→export const connectionStatus = httpAction(async (ctx, request) => {
 56→  try {
 57→    const auth = await authenticateRequest(ctx, request);
 58→    if (auth.error) return auth.error;
 59→    const user = auth.user!;
 60→
 61→    const account = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
 62→      userId: user._id,
 63→      provider: "GOOGLE",
 64→    });
 65→
 66→    if (!account) {
 67→      return jsonResponse({ connected: false });
 68→    }
 69→
 70→    return jsonResponse({
