40→	resp, err := client.ConnectGmail(af.Token)
41→	if err != nil {
42→		return fmt.Errorf("connect failed: %w", err)
43→	}
44→
45→	if resp.AlreadyConnected {
46→		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Gmail already connected (%s)\n", resp.Email)
47→		if project.IsNurgeProject(".") {
