101→// GET /api/connect-success — success page shown after Gmail OAuth completes
102→export const connectSuccess = httpAction(async () => {
103→  const html = `<!DOCTYPE html>
104→<html>
105→<head>
106→  <meta charset="utf-8">
107→  <meta name="viewport" content="width=device-width, initial-scale=1">
108→  <title>Gmail Connected — Nurge</title>
109→  <style>
110→    body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; display: flex; align-items: center; justify-content: center; min-height: 100vh; margin: 0; background: #fafafa; color: #111; }
111→    .card { text-align: center; padding: 3rem 2rem; }
112→    .check { font-size: 3rem; margin-bottom: 1rem; }
113→    h1 { font-size: 1.5rem; font-weight: 600; margin: 0 0 0.5rem; }
114→    p { color: #666; margin: 0; }
115→  </style>
116→</head>
117→<body>
118→  <div class="card">
119→    <div class="check">&#10003;</div>
120→    <h1>Gmail connected</h1>
121→    <p>You can close this tab and return to your terminal.</p>
122→  </div>
