import { httpRouter } from "convex/server";
import { unipileWebhook, unipileAccountCallback } from "./webhook";
import { sendEmail } from "./sendApi";
import { googleAuth, validateToken, revokeToken } from "./auth";
import { connectGmail, connectionStatus, connectSuccess, syncEmails } from "./connect";

const http = httpRouter();

// ── Auth ─────────────────────────────────────────────────────────────

http.route({
  path: "/api/google-auth",
  method: "POST",
  handler: googleAuth,
});

http.route({
  path: "/api/validate-token",
  method: "POST",
  handler: validateToken,
});

http.route({
  path: "/api/revoke-token",
  method: "POST",
  handler: revokeToken,
});

// ── Unipile ──────────────────────────────────────────────────────────

http.route({
  path: "/api/unipile-webhook",
  method: "POST",
  handler: unipileWebhook,
});

http.route({
  path: "/api/unipile-account-callback",
  method: "POST",
  handler: unipileAccountCallback,
});

// ── CLI API ──────────────────────────────────────────────────────────

http.route({
  path: "/api/send-email",
  method: "POST",
  handler: sendEmail,
});

// ── Connect ─────────────────────────────────────────────────────────

http.route({
  path: "/api/connect-gmail",
  method: "POST",
  handler: connectGmail,
});

http.route({
  path: "/api/connection-status",
  method: "GET",
  handler: connectionStatus,
});

http.route({
  path: "/api/connect-success",
  method: "GET",
  handler: connectSuccess,
});

http.route({
  path: "/api/sync-emails",
  method: "POST",
  handler: syncEmails,
});

export default http;

