  1→import { v } from "convex/values";
  2→import { httpAction, internalQuery, internalMutation } from "./_generated/server";
  3→import { api, internal } from "./_generated/api";
  4→
  5→// Unipile webhook receiver — handles new emails, tracking, account status
  6→export const unipileWebhook = httpAction(async (ctx, request) => {
  7→  // Verify Unipile-Auth shared secret
  8→  const secret = process.env.UNIPILE_WEBHOOK_SECRET;
  9→  const authHeader = request.headers.get("Unipile-Auth");
 10→
 11→  if (secret && authHeader !== secret) {
 12→    console.error("Webhook auth failed: invalid Unipile-Auth header");
 13→    return new Response("Unauthorized", { status: 401 });
 14→  }
 15→
 16→  try {
 17→    const payload = await request.json();
 18→    const eventType = payload.event || payload.type;
 19→
 20→    switch (eventType) {
 21→      case "new_email":
 22→      case "mail.received":
 23→        await handleNewEmail(ctx, payload);
 24→        break;
 25→
 26→      case "email_tracking":
 27→      case "mail.tracking":
 28→        // Log open/click events — useful for analytics
 29→        console.log("Email tracking event:", JSON.stringify(payload));
 30→        break;
 31→
 32→      case "account.status":
 33→      case "account_status":
 34→        await handleAccountStatus(ctx, payload);
 35→        break;
 36→
 37→      default:
 38→        console.log("Unknown webhook event:", eventType, JSON.stringify(payload));
 39→    }
 40→
 41→    return new Response("OK", { status: 200 });
 42→  } catch (error: any) {
 43→    console.error("Webhook processing error:", error);
 44→    return new Response("Internal error", { status: 500 });
 45→  }
 46→});
 47→
 48→async function handleNewEmail(ctx: any, payload: any) {
 49→  const email = payload.data || payload;
 50→  const providerId = email.provider_id
 51→    ? JSON.stringify(email.provider_id)
 52→    : "";
 53→  const accountId = email.account_id || "";
 54→  const from = email.from?.identifier || email.from_email || "";
 55→  const threadId = email.thread_id || "";
 56→
 57→  // Find the Unipile account to get the userId
 58→  const account = accountId
 59→    ? await ctx.runQuery(internal.webhook.findAccountByUnipileId, {
 60→        unipileAccountId: accountId,
 61→      })
 62→    : null;
 63→
 64→  if (!account) {
 65→    console.log("No matching Unipile account for:", accountId);
 66→    return;
 67→  }
 68→
 69→  // Check if this email is on a thread with an active enrollment
 70→  if (threadId || providerId) {
 71→    await ctx.runMutation(internal.webhook.processReply, {
 72→      userId: account.userId,
 73→      fromEmail: from,
 74→      threadId,
 75→      providerId,
 76→      messageId: email.id || "",
 77→      subject: email.subject || "",
 78→      snippet: email.body_plain?.substring(0, 200) || "",
 79→    });
 80→  }
 81→}
 82→
 83→async function handleAccountStatus(ctx: any, payload: any) {
 84→  const data = payload.data || payload;
 85→  const accountId = data.account_id || "";
 86→  const status = data.status || "";
 87→
 88→  if (status === "disconnected" || status === "error") {
 89→    const account = await ctx.runQuery(
 90→      internal.webhook.findAccountByUnipileId,
 91→      { unipileAccountId: accountId }
 92→    );
 93→
 94→    if (account) {
 95→      await ctx.runMutation(internal.webhook.markMailboxAuthExpired, {
 96→        userId: account.userId,
 97→        unipileAccountId: accountId,
 98→      });
 99→    }
100→  }
101→}
102→
103→// Unipile account callback — called when user completes hosted auth
104→export const unipileAccountCallback = httpAction(async (ctx, request) => {
105→  try {
106→    const payload = await request.json();
107→    const accountId = payload.account_id || "";
108→    const userId = payload.name || ""; // We pass nurge_user_id as 'name'
109→    const email = payload.identifier || "";
110→
111→    if (!accountId || !userId) {
112→      return new Response("Missing account_id or name", { status: 400 });
113→    }
114→
115→    await ctx.runMutation(internal.webhook.registerUnipileAccount, {
116→      userId,
117→      unipileAccountId: accountId,
118→      provider: "GOOGLE", // TODO: detect from payload
119→      email,
120→    });
121→
122→    // Schedule backfill asynchronously (can take minutes for large mailboxes)
123→    await ctx.scheduler.runAfter(0, api.unipile.backfillEmails, {
124→      userId,
125→      unipileAccountId: accountId,
126→    });
127→
128→    return new Response("OK", { status: 200 });
129→  } catch (error: any) {
130→    console.error("Account callback error:", error);
131→    return new Response("Internal error", { status: 500 });
132→  }
133→});
134→
135→// --- Internal functions used by webhook handlers ---
136→
137→export const findAccountByUnipileId = internalQuery({
138→  args: { unipileAccountId: v.string() },
139→  handler: async (ctx, args) => {
140→    return await ctx.db
141→      .query("unipileAccounts")
142→      .withIndex("by_unipile_id", (q) =>
143→        q.eq("unipileAccountId", args.unipileAccountId)
144→      )
145→      .first();
146→  },
147→});
148→
149→export const processReply = internalMutation({
150→  args: {
151→    userId: v.string(),
152→    fromEmail: v.string(),
153→    threadId: v.string(),
154→    providerId: v.string(),
155→    messageId: v.string(),
156→    subject: v.optional(v.string()),
157→    snippet: v.optional(v.string()),
158→  },
159→  handler: async (ctx, args) => {
160→    // Find active enrollments for this contact
161→    const enrollments = await ctx.db
162→      .query("sequenceEnrollments")
163→      .withIndex("by_contact", (q) =>
164→        q.eq("userId", args.userId).eq("contactEmail", args.fromEmail)
165→      )
166→      .collect();
167→
168→    const activeEnrollments = enrollments.filter(
169→      (e) => e.status === "active" || e.status === "paused"
170→    );
171→
172→    if (activeEnrollments.length === 0) return;
173→
174→    // Get sync version
175→    const syncState = await ctx.db
176→      .query("syncState")
177→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
178→      .first();
179→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
180→
181→    // Stop ALL active enrollments for this contact
182→    for (const enrollment of activeEnrollments) {
183→      await ctx.db.patch(enrollment._id, {
184→        status: "stopped",
185→        statusReason: "reply received",
186→        replyState: "needs_classification",
187→        lastReplyAt: new Date().toISOString(),
188→        nextDueAt: "",
189→        syncVersion: version,
190→      });
191→
192→      // Cancel all pending tasks
193→      const tasks = await ctx.db
194→        .query("followUpTasks")
195→        .withIndex("by_enrollment", (q) =>
196→          q.eq("enrollmentId", enrollment.externalId)
197→        )
198→        .collect();
199→
200→      for (const task of tasks) {
201→        if (task.status === "open") {
