import { v } from "convex/values";
import { httpAction, internalMutation, internalQuery } from "./_generated/server";
import { internal } from "./_generated/api";

// ── Helpers ──────────────────────────────────────────────────────────

function jsonResponse(data: unknown, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });
}

function generateToken(): string {
  const chars = "REDACTED";
  const arr = new Uint8Array(64);
  crypto.getRandomValues(arr);
  return Array.from(arr, (b) => chars[b % chars.length]).join("");
}

// ── Internal queries/mutations ───────────────────────────────────────

export const findUserByEmail = internalQuery({
  args: { email: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("users")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
  },
});

export const findUserByToken = internalQuery({
  args: { token: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("users")
      .withIndex("by_token", (q) => q.eq("token", args.token))
      .first();
  },
});

export const createUser = internalMutation({
  args: { email: v.string(), name: v.string(), token: v.string() },
  handler: async (ctx, args) => {
    await ctx.db.insert("users", {
      email: args.email,
      name: args.name,
      token: args.token,
      createdAt: new Date().toISOString(),
    });
  },
});

export const updateUserToken = internalMutation({
  args: { userId: v.id("users"), token: v.string(), name: v.optional(v.string()) },
  handler: async (ctx, args) => {
    const patch: Record<string, string> = { token: args.token };
    if (args.name) {
      patch.name = args.name;
    }
    await ctx.db.patch(args.userId, patch);
  },
});

export const clearUserToken = internalMutation({
  args: { userId: v.id("users") },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.userId, { token: "" });
  },
});

// ── HTTP Handlers ────────────────────────────────────────────────────

/**
 * POST /api/google-auth
 * Receives a Google ID token, verifies it, creates/finds user, returns Nurge token.
 */
export const googleAuth = httpAction(async (ctx, request) => {
  try {
    const body = await request.json();
    const idToken = body.id_token;
    if (!idToken) {
      return jsonResponse({ error: "Missing id_token" }, 400);
    }

    // Verify ID token with Google
    const googleResp = await fetch(
      `https://oauth2.googleapis.com/tokeninfo?id_token=${idToken}`
    );
    if (!googleResp.ok) {
      return jsonResponse({ error: "Invalid Google ID token" }, 401);
    }

    const googleUser = await googleResp.json();
    const email: string = googleUser.email;
    const name: string = googleUser.name || email.split("@")[0];

    if (!email) {
      return jsonResponse({ error: "No email in Google token" }, 400);
    }

    // Find or create user
    const existing = await ctx.runQuery(internal.auth.findUserByEmail, { email });
    const token = generateToken();

    if (existing) {
      await ctx.runMutation(internal.auth.updateUserToken, {
        userId: existing._id,
        token,
        name,
      });
    } else {
      await ctx.runMutation(internal.auth.createUser, {
        email,
        name,
        token,
      });
    }

    return jsonResponse({ token, email, name });
  } catch (e: any) {
    return jsonResponse({ error: e.message || "Internal error" }, 500);
  }
});

/**
 * POST /api/validate-token
 * Validates a Nurge session token.
 */
export const validateToken = httpAction(async (ctx, request) => {
  try {
    const body = await request.json();
    const token = body.token;
    if (!token) {
      return jsonResponse({ valid: false }, 400);
    }

    const user = await ctx.runQuery(internal.auth.findUserByToken, { token });

    if (!user) {
      return jsonResponse({ valid: false });
    }

    return jsonResponse({
      valid: true,
      user: { email: user.email, name: user.name },
    });
  } catch {
    return jsonResponse({ valid: false }, 500);
  }
});

/**
 * POST /api/revoke-token
 * Clears the user's session token.
 */
export const revokeToken = httpAction(async (ctx, request) => {
  try {
    const body = await request.json();
    const token = body.token;
    if (!token) {
      return jsonResponse({ error: "Missing token" }, 400);
    }

    const user = await ctx.runQuery(internal.auth.findUserByToken, { token });

    if (user) {
      await ctx.runMutation(internal.auth.clearUserToken, {
        userId: user._id,
      });
    }

    return jsonResponse({ ok: true });
  } catch {
    return jsonResponse({ ok: true }); // Best effort
  }
});

