package cmd

import (
	"context"
	"fmt"

	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/connector"
	"github.com/spf13/cobra"
)

var connectCredentials string

var connectCmd = &cobra.Command{
	Use:   "connect <connector>",
	Short: "Connect a service (gmail, hubspot)",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		if !project.IsNurgeProject(".") {
			return fmt.Errorf("no nurge project found. Run `nurge` first to initialize")
		}

		id := args[0]
		registry := connector.DefaultRegistry()

		var def *connector.ConnectorDef
		for i := range registry {
			if registry[i].ID == id {
				def = &registry[i]
				break
			}
		}
		if def == nil {
			fmt.Printf("Unknown connector: %s\n", id)
			fmt.Println("Available connectors: gmail, hubspot")
			return fmt.Errorf("unknown connector: %s", id)
		}

		conn := connector.NewFromDef(*def, connectCredentials)

		fmt.Printf("Opening browser for %s...\n", def.Name)
		result, err := conn.Connect(context.Background())
		if err != nil {
			return fmt.Errorf("%s connection failed: %w", def.Name, err)
		}

		if err := project.SetConnector(def.ID, def.Type, result.Account); err != nil {
			return fmt.Errorf("saving config: %w", err)
		}

		fmt.Printf("\033[32m✓\033[0m %s connected (%s)\n", def.Name, result.Account)
		return nil
	},
}

func init() {
	connectCmd.Flags().StringVar(&connectCredentials, "credentials", "", "Path to OAuth credentials.json (Gmail only)")
	rootCmd.AddCommand(connectCmd)
}

