package cmd

import (
	"context"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/update"
)

var updatePre bool

var updateCmd = &cobra.Command{
	Use:         "update [version]",
	Short:       "Update nurge to the latest version",
	Long:        "Downloads and replaces the current nurge binary.\n\nExamples:\n  nurge update          # Latest stable\n  nurge update --pre    # Latest including prereleases\n  nurge update v0.2.0   # Specific version",
	Args:        cobra.MaximumNArgs(1),
	Annotations: map[string]string{"skipAuth": "true"},
	RunE: func(cmd *cobra.Command, args []string) error {
		var target string
		if len(args) == 1 {
			target = args[0]
		}
		return update.SelfUpdate(context.Background(), buildVersion, target, updatePre)
	},
}

func init() {
	updateCmd.Flags().BoolVar(&updatePre, "pre", false, "Include prerelease versions")
	rootCmd.AddCommand(updateCmd)
}

