// SendEmail calls the Convex /api/send-email endpoint.
func (c *ConvexClient) SendEmail(token string, req SendEmailRequest) (*SendEmailResponse, error) {
	body, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("marshaling request: %w", err)
	}

	httpReq, err := http.NewRequest("POST", c.baseURL+"/api/send-email", bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Authorization", "Bearer "+token)

	resp, err := c.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("calling send-email: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	var result SendEmailResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing response: %w", err)
	}

	if !result.OK {
		return &result, fmt.Errorf("%s", result.Error)
	}
	return &result, nil
}

// RevokeToken revokes a token on the Convex backend.
func (c *ConvexClient) RevokeToken(token string) error {
	body, _ := json.Marshal(map[string]string{"token": token})
	resp, err := c.httpClient.Post(
