package cmd

import (
	"fmt"
	"os"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/util"
)

var connectCmd = &cobra.Command{
	Use:   "connect <service>",
	Short: "Connect a service (gmail)",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id := args[0]
		switch id {
		case "gmail":
			return connectGmail()
		default:
			fmt.Printf("Unknown service: %s\n", id)
			fmt.Println("Available: gmail")
			return fmt.Errorf("unknown service: %s", id)
		}
	},
}

func connectGmail() error {
	af, err := account.LoadAuth()
	if err != nil || af.Token == "" {
		return fmt.Errorf("not logged in. Run: nurge account login")
	}

	client := account.NewConvexClient(GetConvexURL())

	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
	resp, err := client.ConnectGmail(af.Token)
	if err != nil {
		return fmt.Errorf("connect failed: %w", err)
	}

	if resp.AlreadyConnected {
		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Gmail already connected (%s)\n", resp.Email)
		if project.IsNurgeProject(".") {
			_ = project.SetConnector("gmail", "email", resp.Email)
		}
		return nil
	}

	fmt.Fprintf(os.Stderr, "  Opening browser to connect Gmail...\n")
	if err := util.OpenBrowser(resp.URL); err != nil {
		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
	}

	fmt.Fprintf(os.Stderr, "  Waiting for Gmail connection...")
	timeout := time.After(5 * time.Minute)
	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-timeout:
			fmt.Fprintf(os.Stderr, "\n")
			return fmt.Errorf("timed out waiting for Gmail connection")
		case <-ticker.C:
			status, err := client.ConnectionStatus(af.Token)
			if err != nil {
				continue
			}
			if status.Connected {
				fmt.Fprintf(os.Stderr, "\n  \033[32m✓\033[0m Gmail connected (%s)\n", status.Email)
				if project.IsNurgeProject(".") {
					_ = project.SetConnector("gmail", "email", status.Email)
				}
				return nil
			}
			fmt.Fprintf(os.Stderr, ".")
		}
	}
}

func init() {
	rootCmd.AddCommand(connectCmd)
}

